   151→
   152→    // #87: Get user's provider preference and budget from settings
   153→    let providerPreference: AIProvider | 'auto' | undefined;
   154→    let userSettings: { provider: string; budgetLimit: number; totalSpent: number } | null = null;
   155→    if (userId) {
   156→      try {
   157→        userSettings = await prisma.settings.findUnique({
   158→          where: { userId },
   159→          select: { provider: true, budgetLimit: true, totalSpent: true },
   160→        });
   161→        if (userSettings?.provider && (userSettings.provider === 'azure' || userSettings.provider === 'ollama')) {
   162→          providerPreference = userSettings.provider;
   163→        }
   164→
   165→        // Check budget limit (WAVE 3: Token budget enforcement)
   166→        if (userSettings && userSettings.totalSpent >= userSettings.budgetLimit) {
   167→          logger.warn('Budget limit exceeded', {
   168→            userId,
   169→            totalSpent: userSettings.totalSpent,
   170→            budgetLimit: userSettings.budgetLimit,
   171→          });
   172→          return NextResponse.json(
   173→            {
   174→              error: 'Budget limit exceeded',
   175→              message: `You have reached your budget limit of $${userSettings.budgetLimit.toFixed(2)}. Please increase your budget in settings.`,
   176→              totalSpent: userSettings.totalSpent,
   177→              budgetLimit: userSettings.budgetLimit,
   178→            },
   179→            { status: 402 }
   180→          );
   181→        }
   182→      } catch (e) {
   183→        // Settings lookup failure should not block chat
   184→        logger.debug('Failed to load provider preference', { error: String(e) });
   185→      }
   186→    }
   187→
   188→    // Build enhanced system prompt with tool context
   189→    let enhancedSystemPrompt = systemPrompt;
   190→    if (requestedTool && TOOL_CONTEXT[requestedTool]) {
   191→      enhancedSystemPrompt = `${systemPrompt}\n\n${TOOL_CONTEXT[requestedTool]}`;
   192→      logger.debug('Tool context injected', { requestedTool, maestroId });
   193→    }
   194→
   195→    // Inject conversation memory if enabled and user is authenticated (ADR 0021)
   196→    let hasMemory = false;
   197→    if (enableMemory && userId && maestroId) {
   198→      try {
   199→        const memory = await loadPreviousContext(userId, maestroId);
   200→        if (memory.recentSummary || memory.keyFacts.length > 0) {
   201→          enhancedSystemPrompt = enhanceSystemPrompt({
   202→            basePrompt: enhancedSystemPrompt,
   203→            memory,
   204→            safetyOptions: {
