   286→              toolCall: toolCall.function.name,
   287→              error: String(toolError),
   288→            });
   289→            const args = JSON.parse(toolCall.function.arguments || '{}');
   290→            toolResults.push({
   291→              id: toolCall.id,
   292→              type: toolCall.function.name,
   293→              name: toolCall.function.name,
