   346→        } catch (e) {
   347→          // Budget update failure should not block the response
   348→          logger.warn('Failed to update budget', { userId, error: String(e) });
   349→        }
   350→      }
   351→
   352→      return NextResponse.json({
   353→        content: sanitized.text,
   354→        provider: result.provider,
   355→        model: result.model,
   356→        usage: result.usage,
   357→        hasMemory,
   358→        maestroId,
   359→        sanitized: sanitized.modified,
   360→      });
   361→    } catch (providerError) {
   362→      // Provider-specific error handling
   363→      const errorMessage =
   364→        providerError instanceof Error
