   201→              totalSpent: state.totalSpent,  // #88: Now persisted
   202→              language: state.appearance.language,
   203→              accentColor: state.appearance.accentColor,
   204→            }),
   205→          });
   206→
   207→          // Sync profile
   208→          await fetch('/api/user/profile', {
   209→            method: 'PUT',
   210→            headers: { 'Content-Type': 'application/json' },
   211→            body: JSON.stringify({
   212→              name: state.studentProfile.name,
   213→              age: state.studentProfile.age,
   214→              schoolYear: state.studentProfile.schoolYear,
   215→              schoolLevel: state.studentProfile.schoolLevel,
   216→              gradeLevel: state.studentProfile.gradeLevel,
   217→              learningGoals: state.studentProfile.learningGoals,
   218→              // Character preferences
   219→              preferredCoach: state.studentProfile.preferredCoach,
   220→              preferredBuddy: state.studentProfile.preferredBuddy,
   221→              accessibility: {
   222→                fontSize: state.studentProfile.fontSize,
   223→                highContrast: state.studentProfile.highContrast,
   224→                dyslexiaFont: state.studentProfile.dyslexiaFont,
   225→                voiceEnabled: state.studentProfile.voiceEnabled,
   226→                simplifiedLanguage: state.studentProfile.simplifiedLanguage,
   227→                adhdMode: state.studentProfile.adhdMode,
   228→              },
   229→            }),
   230→          });
   231→
   232→          set({ lastSyncedAt: new Date(), pendingSync: false });
   233→        } catch (error) {
   234→          logger.error('Settings sync failed', { error: String(error) });
   235→        }
   236→      },
   237→
   238→      loadFromServer: async () => {
   239→        try {
   240→          const [settingsRes, profileRes] = await Promise.all([
   241→            fetch('/api/user/settings'),
   242→            fetch('/api/user/profile'),
   243→          ]);
   244→
   245→          if (settingsRes.ok) {
   246→            const settings = await settingsRes.json();
   247→            set((state) => ({
   248→              theme: settings.theme ?? state.theme,
   249→              provider: settings.provider ?? state.provider,
   250→              model: settings.model ?? state.model,
   251→              budgetLimit: settings.budgetLimit ?? state.budgetLimit,
   252→              totalSpent: settings.totalSpent ?? state.totalSpent,  // #88: Load from server
   253→              appearance: {
   254→                ...state.appearance,
   255→                language: settings.language ?? state.appearance.language,
   256→                accentColor: settings.accentColor ?? state.appearance.accentColor,
   257→              },
   258→            }));
   259→          }
   260→
   261→          if (profileRes.ok) {
   262→            const profile = await profileRes.json();
   263→            if (profile) {
   264→              const accessibility = profile.accessibility || {};
   265→              set((state) => ({
   266→                studentProfile: {
   267→                  ...state.studentProfile,
   268→                  name: profile.name ?? state.studentProfile.name,
   269→                  age: profile.age ?? state.studentProfile.age,
   270→                  schoolYear: profile.schoolYear ?? state.studentProfile.schoolYear,
   271→                  schoolLevel: profile.schoolLevel ?? state.studentProfile.schoolLevel,
   272→                  gradeLevel: profile.gradeLevel ?? state.studentProfile.gradeLevel,
   273→                  learningGoals: profile.learningGoals ?? state.studentProfile.learningGoals,
   274→                  // Character preferences
   275→                  preferredCoach: profile.preferredCoach ?? state.studentProfile.preferredCoach,
